import{_ as b,o as a,c as e,j as A,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const s="data:image/jpeg;base64,",x=JSON.parse('{"title":"2.枪击系","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/人格面具/攻击系/2.枪击系.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/人格面具/攻击系/2.枪击系.md"}'),p={name:"4.资源分区/6.技艺及称号/通用及综合类/人格面具/攻击系/2.枪击系.md"};function H(d,r,E,o,f,i){return a(),e("div",null,[...r[0]||(r[0]=[A("h1",{id:"_2-枪击系",tabindex:"-1"},[t("2.枪击系 "),A("a",{class:"header-anchor",href:"#_2-枪击系","aria-label":'Permalink to "2.枪击系"'},"​")],-1),A("table",{class:"bannerparthead"},[A("tbody",null,[A("tr",{id:"hdr"},[A("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),n('<h1 id="枪击系" tabindex="-1">枪击系：<img src="'+s+'" alt=""> <a class="header-anchor" href="#枪击系" aria-label="Permalink to &quot;枪击系：![](./枪击.jpg)&quot;">​</a></h1><p>枪击系：<br> 在判断枪击系的伤害类型时，都为物理伤害下属的穿刺伤害，并且具有枪械概念或者子弹概念。枪击系技能在释放时不像除物理系以外的技能一样消耗SP，而是消耗HP（血量），消耗的HP无法通过除武道的诀窍以外的任何方式被减免、吸收，并且还能将使用者使用的枪械武器加入到技能释放当中，释放的技能加入枪械武器的武器伤害、特性，但是无法使用枪械武器的射程，会消耗相应的子弹数量。</p><p>【指弹】<br> 等级：C<br> 习得提供能力值：4<br> 消耗HP：2<br> 动作：标准<br> 射程：1米×【决心】+1米×【力】<br> 范围：单体<br> 持续：立即<br> 对抗：防御<br> 效果：造成【中量】枪击属性的穿刺伤害，具有【中量】高速效果。如果加入枪械武器会消耗1颗子弹。<br> 遗忘提供能力值：8</p><p>【双重射击】<br> 等级：B<br> 习得提供能力值：8<br> 消耗HP：4<br> 动作：标准<br> 射程：5米×【决心】+4米×【力】<br> 范围：单体<br> 持续：立即<br> 对抗：防御<br> 效果：造成两次【小量】枪击属性的穿刺伤害。如果加入枪械武器会消耗2颗子弹。<br> 遗忘提供能力值：16</p><p>【织梦针】<br> 等级：B<br> 习得提供能力值：8<br> 消耗HP：4<br> 动作：标准<br> 射程：5米×【决心】+4米×【力】<br> 范围：单体<br> 持续：立即<br> 对抗：防御与强韧<br> 效果：造成【小量】枪击属性的穿刺伤害，【中概率】产生【睡眠】效果，强韧豁免豁免对抗本效果。如果加入枪械武器会随机消耗3至6颗子弹。<br> 遗忘提供能力值：16</p><p>【一枪毙命】<br> 等级：S<br> 习得前提：拥有认知要素【枪】<br> 习得提供能力值：32<br> 消耗HP：8<br> 动作：标准<br> 射程：20米×【决心】+20米×【力】<br> 范围：单体<br> 持续：立即<br> 对抗：防御<br> 效果：造成【特大量】枪击属性的穿刺伤害，在这次攻击中无视目标的闪避防御、洞察防御这是S级时空来源的效果、【特大量】的全伤害吸收+DR/-（合计计算无视的数值），并且全DP取10，但是无加骰，如果这次技能击杀目标还能禁止目标SSS级及以下的复活能力发动。【高概率】产生【暴击】效果。如果加入枪械武器会消耗1颗子弹。<br> 遗忘提供能力值：64</p><p>【三连倒】<br> 等级：B<br> 习得提供能力值：8<br> 消耗HP：4<br> 动作：标准<br> 射程：4米×【决心】+2米×【魔】<br> 范围：射程内所有敌方目标<br> 持续：立即<br> 对抗：反射<br> 效果：造成三次【小量】枪击属性的穿刺伤害，前两次攻击的伤害减半，仅最后一次攻击会造成全额伤害。如果加入枪械武器会消耗3×【攻击目标数量】颗子弹。<br> 遗忘提供能力值：16</p><p>【至高魔弹】<br> 等级：A<br> 习得前提：拥有认知要素【枪】<br> 习得提供能力值：16<br> 消耗HP：8<br> 动作：整轮<br> 射程：等于敏感范围<br> 范围：射程内所有敌方目标<br> 持续：立即<br> 对抗：反射<br> 效果：技能释放时召唤者的敏感范围额外提升【小量】倍数，对可感知到的目标造成【特大量】枪击属性的穿刺伤害，并且无视中间的一切障碍物，直接攻击目标，这是S级时空来源的传送效果，目标的反射豁免会因次承受【特大量】环境减值。如果加入枪械武器会消耗1颗子弹。<br> 遗忘提供能力值：32</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const g=b(p,[["render",H]]);export{x as __pageData,g as default};
